<template>
   <div>
      <!-- 面包屑 -->
      <el-breadcrumb separator-class="el-icon-arrow-right">
         <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
         <el-breadcrumb-item>订单管理</el-breadcrumb-item>
         <el-breadcrumb-item>订单列表</el-breadcrumb-item>
      </el-breadcrumb>

      <!-- 卡片 -->
      <el-card class="box-card">
         <!-- 搜索框 -->
         <el-input placeholder="请输入内容" class="input-with-select">
            <el-button slot="append" icon="el-icon-search"></el-button>
         </el-input>
         <!-- 表格 -->
         <el-table :data="tableData" border style="width: 100%">
            <el-table-column type="index" label="#">
            </el-table-column>
            <el-table-column prop="order_number" label="订单编号" width="200">
            </el-table-column>
            <el-table-column prop="order_price" label="订单价格">
            </el-table-column>
            <el-table-column label="是否付款">
               <template slot-scope="scope">
                  <el-tag type="danger" v-if="scope.row.is_send==='否'">未付款</el-tag>
                  <el-tag v-if="scope.row.is_send==='是'">已付款</el-tag>
               </template>
            </el-table-column>
            <el-table-column prop="is_send" label="是否发货">
            </el-table-column>
            <el-table-column prop="update_time" label="下单时间">
               <template slot-scope="scope">
                  {{scope.row.update_time|timefn}}
               </template>
            </el-table-column>
            <el-table-column label="操作">
               <template slot-scope="scope">
                  <!-- <el-tag type="danger" v-if="scope.row.is_send==='否'">未付款</el-tag> -->
                  <el-tooltip :enterable="false" content="修改订单地址" placement="top">
                     <el-button type="primary" @click="dialogVisible = true" icon="el-icon-edit" circle></el-button>
                   </el-tooltip>

                   <el-tooltip :enterable="false" content="物流信息" placement="top">
                     <el-button type="warning" @click="" icon="el-icon-star-off" circle></el-button>
                   </el-tooltip>
               </template>
            </el-table-column>
         </el-table>
         <!-- 分页 -->
         <el-pagination @size-change="handleSizeChange" @current-change="handleCurrentChange"
            :page-sizes="[6, 15, 20, 25]" :page-size="100" layout="total, sizes, prev, pager, next, jumper"
            :total="total">
         </el-pagination>
      </el-card>


               <!-- 修改地址弹出框 -->
               <el-dialog
               title="修改地址"
               :visible.sync="dialogVisible"
               width="30%">
               <!-- <span>这是一段信息</span> -->
               <span slot="footer" class="dialog-footer">
                  <el-button @click="dialogVisible = false">取 消</el-button>
                  <el-button type="primary" @click="dialogVisible = false">确 定</el-button>
               </span>
            </el-dialog>


   </div>
</template>

<script>
   export default {
      data() {
         return {
            dialogVisible: false,
            tableData: [],
            total: 0,
            // | query                | 查询参数        | 可以为空 |
            // | pagenum              | 当前页码        | 不能为空 |
            // | pagesize             | 每页显示条数    | 不能为空 |
            // | user_id              | 用户 ID         | 可以为空 |
            // | pay_status           | 支付状态        | 可以为空 |
            // | is_send              | 是否发货        | 可以为空 |
            // | order_fapiao_title   | ['个人','公司'] | 可以为空 |
            // | order_fapiao_company | 公司名称        | 可以为空 |
            // | order_fapiao_content | 发票内容        | 可以为空 |
            // | consignee_addr       | 发货地址        | 可以为空 |
            user:{
               query:'',
               pagenum:'1',
               pagesize:'6',
               user_id:'',
               pay_status:'',
               is_send:'',
               order_fapiao_title:'',
               order_fapiao_company:'',
               order_fapiao_content:'',
               consignee_addr:''
            }
         };
      },
      created() {

      },
      mounted() {
         this.ajax()
      },
      methods: {
         async ajax() {
            let { data } = await this.$http.get(`/orders?pagenum=${this.user.pagenum}&pagesize=${this.user.pagesize}`)
            console.log(data)
            this.tableData = data.data.goods
            //   console.log(this.tableData)
            this.total=data.data.total
         },
         handleSizeChange(val) {
            // console.log(`每页 ${val} 条`);
            this.user.pagesize=val;
            this.ajax()
         },
         handleCurrentChange(val) {
            // console.log(`当前页: ${val}`);
            this.user.pagenum=val;
            this.ajax()
         }
      }
   };
</script>

<style scoped>
   .box-card {
      margin-top: 10px;
   }
</style>